import{_ as e,o as a,c as i,ag as o}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"Migration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/migration.md","filePath":"guide/migration.md"}'),n={name:"guide/migration.md"};function r(d,t,s,l,c,p){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="migration" tabindex="-1">Migration <a class="header-anchor" href="#migration" aria-label="Permalink to &quot;Migration&quot;">​</a></h1><p>SendGrail can automatically import SMTP settings from other popular WordPress email plugins. Migration is available during the Setup Wizard or as a standalone page.</p><h2 id="supported-plugins" tabindex="-1">Supported Plugins <a class="header-anchor" href="#supported-plugins" aria-label="Permalink to &quot;Supported Plugins&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Plugin</th><th>Detection Method</th></tr></thead><tbody><tr><td>WP Mail SMTP</td><td>Reads <code>wp_mail_smtp</code> option</td></tr><tr><td>Post SMTP</td><td>Reads <code>postman_state</code> and related options</td></tr><tr><td>FluentSMTP</td><td>Reads <code>fluentmail-settings</code> option</td></tr><tr><td>Easy WP SMTP</td><td>Reads <code>swpsmtp_options</code> option</td></tr></tbody></table><h2 id="how-detection-works" tabindex="-1">How Detection Works <a class="header-anchor" href="#how-detection-works" aria-label="Permalink to &quot;How Detection Works&quot;">​</a></h2><p>When you visit the migration page (or reach the migration step in the Setup Wizard), SendGrail queries the <code>wp_options</code> table for known option keys used by each supported plugin. If a matching option is found and contains valid SMTP configuration data, that plugin appears in the list of available migrations.</p><p>Detection happens automatically -- you do not need to have the original plugin activated. As long as its settings remain in the database, SendGrail can read them.</p><h2 id="what-gets-imported" tabindex="-1">What Gets Imported <a class="header-anchor" href="#what-gets-imported" aria-label="Permalink to &quot;What Gets Imported&quot;">​</a></h2><p>The following settings are extracted and mapped to a new SendGrail connection:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td><code>host</code></td><td>SMTP server hostname</td></tr><tr><td><code>port</code></td><td>SMTP server port</td></tr><tr><td><code>encryption</code></td><td>Encryption type (TLS, SSL, or none)</td></tr><tr><td><code>auth</code></td><td>Whether authentication is required</td></tr><tr><td><code>username</code></td><td>SMTP username</td></tr><tr><td><code>password</code></td><td>SMTP password or API key</td></tr><tr><td><code>from_email</code></td><td>Default sender email address</td></tr><tr><td><code>from_name</code></td><td>Default sender display name</td></tr></tbody></table><p>SendGrail normalizes these values across different plugin formats. For example, some plugins store encryption as <code>tls</code> while others use <code>STARTTLS</code> -- SendGrail handles both.</p><h2 id="non-destructive-import" tabindex="-1">Non-Destructive Import <a class="header-anchor" href="#non-destructive-import" aria-label="Permalink to &quot;Non-Destructive Import&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Migration is completely non-destructive. SendGrail reads the original plugin&#39;s settings but never modifies or deletes them. Your original configuration remains intact in the database.</p></div><p>This means you can:</p><ul><li>Keep the original plugin installed (deactivated) as a safety net.</li><li>Roll back to the original plugin at any time without reconfiguring.</li><li>Import the same settings multiple times if needed.</li></ul><h2 id="using-migration" tabindex="-1">Using Migration <a class="header-anchor" href="#using-migration" aria-label="Permalink to &quot;Using Migration&quot;">​</a></h2><h3 id="during-the-setup-wizard" tabindex="-1">During the Setup Wizard <a class="header-anchor" href="#during-the-setup-wizard" aria-label="Permalink to &quot;During the Setup Wizard&quot;">​</a></h3><p>Migration is Step 2 of the Setup Wizard. If compatible plugins are detected, you will see a list with an <strong>Import</strong> button next to each one. Click Import to create a SendGrail connection from those settings. If no plugins are detected, this step is skipped automatically.</p><h3 id="standalone-migration-page" tabindex="-1">Standalone Migration Page <a class="header-anchor" href="#standalone-migration-page" aria-label="Permalink to &quot;Standalone Migration Page&quot;">​</a></h3><p>You can access migration at any time from the SendGrail admin panel by navigating to <code>#/migration</code>. This is useful if you:</p><ul><li>Skipped migration during the wizard.</li><li>Installed a new SMTP plugin after initial setup and want to import its settings.</li><li>Want to re-import settings after making changes in the original plugin.</li></ul><h2 id="after-migration" tabindex="-1">After Migration <a class="header-anchor" href="#after-migration" aria-label="Permalink to &quot;After Migration&quot;">​</a></h2><p>Once settings are imported, SendGrail creates a new connection with the provider automatically identified based on the SMTP host. You should:</p><ol><li><strong>Review the connection</strong> -- Verify that all fields are correct on the Connections page.</li><li><strong>Send a test email</strong> -- Confirm that the imported credentials are still valid.</li><li><strong>Set as default</strong> -- If this should be your primary connection, set it as the default in Settings.</li><li><strong>Deactivate the old plugin</strong> -- Once you have verified everything works, deactivate (but optionally keep installed) the original SMTP plugin to avoid conflicts.</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Do not run two SMTP plugins simultaneously. Both will try to hook into <code>wp_mail()</code>, which can cause unpredictable behavior. Deactivate the original plugin after confirming SendGrail is working.</p></div>',25)])])}const g=e(n,[["render",r]]);export{u as __pageData,g as default};
